from lxml import etree
import xml.etree.ElementTree as ET

def process_soap_request(xml_data):
    # Define DTD validation
    dtd = etree.DTD('path_to_your_dtd_file.dtd')
    
    # Parse XML data with DTD validation
    try:
        root = etree.fromstring(xml_data, parser=etree.XMLParser(dtd_validation=True))
        if not dtd.validate(root):
            raise ValueError("DTD validation failed")
    except etree.XMLSyntaxError as e:
        raise ValueError(f"XML syntax error: {e}")
    
    # Extract SOAP envelope and message body
    envelope = root.find('{http://schemas.xmlsoap.org/soap/envelope/}Envelope')
    if envelope is None:
        raise ValueError("SOAP Envelope not found")
    
    body = envelope.find('{http://schemas.xmlsoap.org/soap/envelope/}Body')
    if body is None:
        raise ValueError("SOAP Body not found")
    
    # Return the message body as a string
    return etree.tostring(body, pretty_print=True).decode('utf-8')

